using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // EF 9 renamed the discriminator property from "Discriminator" to "$type".
            // Existing documents and direct SQL queries reference c.Discriminator.
            b.HasDiscriminator<string>("Discriminator");

            // EF 9 maps the key property directly to JSON "id", removing the
            // shadow __id property. Existing documents store Id separately.
            b.HasShadowId();

            // EF 9 no longer prefixes the discriminator in the JSON id.
            // Existing documents use the format "Product|123".
            b.HasDiscriminatorInJsonId();

            // Removed: HasIndex — Cosmos indexes all properties by default
            // and EF 9 now throws instead of silently ignoring the call.
        });
    }
}
